foreach (var sf in sourceFiles)
{
    Console.WriteLine($"SourceFile: {sf.Name}");
}

// Find CscCommandLineArgs or Csc tasks
var tasks = build.FindChildrenRecursive<Task>();
foreach (var t in tasks)
{
    if (t.Name == "Csc")
    {
        var project = t.GetNearestParent<Project>()?.Name ?? "unknown";
        Console.WriteLine($"\nCsc task in [{project}]:");
        foreach (var child in t.Children)
        {
            if (child is Folder folder && folder.Name == "CommandLineArguments")
            {
                Console.WriteLine($"  CommandLineArgs: {string.Join(" ", folder.Children.Select(c => c.ToString()))}");
            }
            else if (child is Message msg)
            {
                Console.WriteLine($"  Message: {msg.Text}");
            }
        }
    }
}

// Get source file content from SourceFilesCollector
var items = build.FindChildrenRecursive<Item>();
foreach (var item in items)
{
    if (item.Name?.Contains("UserService") == true || item.Name?.Contains("Models") == true || item.Name?.Contains("Program") == true)
    {
        Console.WriteLine($"Item: {item.Name} Text: {item.Text}");
    }
}

// Look for the compiler command line to find source files
var messages = build.FindChildrenRecursive<Message>();
foreach (var m in messages)
{
    if (m.Text?.Contains("UserService") == true || m.Text?.Contains("Models.cs") == true || m.Text?.Contains("Program.cs") == true)
    {
        Console.WriteLine($"Message: {m.Text?.Substring(0, Math.Min(200, m.Text.Length))}");
    }
}
