using Microsoft.Build.Logging.StructuredLogger;
using STask = Microsoft.Build.Logging.StructuredLogger.Task;

var build = BinaryLog.ReadBuild(args[0]);

// Get all errors with full detail
var errors = build.FindChildrenRecursive<Error>();
Console.WriteLine("=== ERRORS ===");
foreach (var e in errors)
{
    var project = e.GetNearestParent<Project>()?.Name ?? "unknown";
    Console.WriteLine($"[{project}] {e.Code}: {e.Text}");
    Console.WriteLine($"  File: {e.File} Line: {e.LineNumber}");
}

// Dump the Csc tasks for failed projects
var tasks = build.FindChildrenRecursive<STask>();
foreach (var t in tasks)
{
    if (t.Name == "Csc")
    {
        var project = t.GetNearestParent<Project>()?.Name ?? "unknown";
        if (project.Contains("Services") || project.Contains("Api"))
        {
            Console.WriteLine($"\n=== Csc [{project}] ===");
            foreach (var child in t.Children)
            {
                Console.WriteLine($"  {child.GetType().Name}: {child}");
            }
        }
    }
}

// Look for dependent project build failures (MSB3202, etc.)
var allErrors = build.FindChildrenRecursive<Error>();
Console.WriteLine("\n=== Project dependency failures ===");
foreach (var e in allErrors)
{
    if (e.Code?.StartsWith("MSB") == true)
    {
        var project = e.GetNearestParent<Project>()?.Name ?? "unknown";
        Console.WriteLine($"[{project}] {e.Code}: {e.Text}");
    }
}

// Check if Api project also has build errors
Console.WriteLine("\n=== Api project errors ===");
foreach (var e in allErrors)
{
    var project = e.GetNearestParent<Project>()?.Name ?? "unknown";
    if (project.Contains("Api"))
        Console.WriteLine($"[{project}] {e.Code}: {e.Text}");
}

// Check if Core project has errors
Console.WriteLine("\n=== Core project errors ===");
foreach (var e in allErrors)
{
    var project = e.GetNearestParent<Project>()?.Name ?? "unknown";
    if (project.Contains("Core"))
        Console.WriteLine($"[{project}] {e.Code}: {e.Text}");
}
