arguments.command:
cd /tmp && cat > ReadBinlog.cs << 'CSHARP'
using Microsoft.Build.Logging.StructuredLogger;
using STask = Microsoft.Build.Logging.StructuredLogger.Task;

var build = BinaryLog.ReadBuild(args[0]);

// Check project-level build results
var projects = build.FindChildrenRecursive<Project>();
Console.WriteLine("=== PROJECT RESULTS ===");
foreach (var p in projects)
{
    var errs = p.FindChildrenRecursive<Error>().Count();
    // Check for "Build FAILED" or target results
    var targets = p.FindChildrenRecursive<Target>();
    bool anyFailed = targets.Any(t => !t.IsLowRelevance && t.Children.OfType<Error>().Any());
    Console.WriteLine($"  {p.Name} (TFM={p.TargetFramework}) Errors={errs}");
}

// Check the UserService.cs source - find it in the Csc command
var cscTasks = build.FindChildrenRecursive<STask>().Where(t => t.Name == "Csc");
foreach (var t in cscTasks)
{
    var project = t.GetNearestParent<Project>()?.Name ?? "unknown";
    Console.WriteLine($"\n=== Csc in {project} ===");
    // Print input items
    var folders = t.Children.OfType<Folder>();
    foreach (var f in folders)
    {
        if (f.Name == "Parameters")
        {
            foreach (var child in f.Children)
            {
                var str = child.ToString();
                if (str?.Contains("Sources") == true || str?.Contains("Reference") == true)
                    Console.WriteLine($"  {str?.Substring(0, Math.Min(200, str.Length))}");
            }
        }
    }
}

// Check if Api compilation was even attempted
Console.WriteLine("\n=== Build target results ===");
foreach (var p in projects)
{
    var targets = p.FindChildrenRecursive<Target>()
        .Where(t => t.Name == "CoreCompile" || t.Name == "Build" || t.Name == "ResolveProjectReferences");
    foreach (var t in targets)
    {
        Console.WriteLine($"  [{p.Name}] {t.Name}");
    }
}
